    return (
        "🏠 <b>Главное меню</b>\n\n"
        f"Ручной анализ: <b>{TICKERS[ticker]['label']}</b> | <b>{INTERVALS[iv]['label']}</b>\n"
        f"Авто: <b>{sub_status}</b>\n"
        f"  ⏰ Рассылка: <b>{AUTO_SEND_INTERVALS[si]['label']}</b>\n"
        f"  📊 TF анализа: <b>{INTERVALS[tf]['label']}</b>\n"
        f"Позиции: <b>{n_pos}</b>"
    )

