# ============================================================
# v7.45 - ADAPTIVE SETUP QUALITY GATE
# ============================================================
# Uses local Testnet lifecycle evidence to lower priority for weak recurring
# conditions. Small samples do not block anything; this is a risk gate, not a
# curve-fitting engine.

_base_testnet_candidate_block_reason_v735_for_v745 = _testnet_candidate_block_reason_v735
_base_demo_scan_row_for_storage_v736_for_v745 = _demo_scan_row_for_storage_v736
_base_demo_candidate_for_storage_v736_for_v745 = _demo_candidate_for_storage_v736

ADAPTIVE_GATE_MIN_CLOSED_V745 = 10
ADAPTIVE_GATE_STRONG_CLOSED_V745 = 30
ADAPTIVE_GATE_MAX_PENALTY_V745 = 18
ADAPTIVE_GATE_BLOCK_PENALTY_V745 = 14
ADAPTIVE_GATE_EXCEPTION_SCORE_V745 = 92
ADAPTIVE_GATE_LOCAL_ROW_LIMIT_V745 = 600


def _adaptive_quality_candidate_keys_v745(candidate):
    candidate = candidate or {}
    ticker = str(candidate.get("ticker") or "").strip()
    interval = str(candidate.get("interval") or "").strip()
    direction = str(candidate.get("direction") or "").strip().lower()
    strategy = str(candidate.get("strategy") or "").strip()
    keys = []
    if ticker:
        keys.append(("ticker", ticker))
    if interval:
        keys.append(("tf", interval))
    if ticker and interval:
        keys.append(("ticker_tf", f"{ticker}:{interval}"))
    if direction:
        keys.append(("direction", direction))
    if strategy:
        keys.append(("strategy", strategy))
    if strategy and interval:
        keys.append(("strategy_tf", f"{strategy}:{interval}"))
    return keys


def _adaptive_quality_local_rows_v745(chat_id=None, limit=ADAPTIVE_GATE_LOCAL_ROW_LIMIT_V745):
    try:
        state = _testnet_lifecycle_load_v740()
        rows = list(state.get("trades") or [])
        if chat_id is not None:
            plan_ids = {
                p.get("plan_id")
                for p in _execution_last_plans_v715(chat_id, int(limit) * 2)
                if p.get("plan_id")
            }
            rows = [row for row in rows if row.get("plan_id") in plan_ids]
        rows.sort(key=lambda x: str(x.get("updated_at") or x.get("created_at") or ""), reverse=True)
        return rows[: int(limit)]
    except Exception as e:
        print(f"  [adaptive_gate_v745] local rows error: {e}")
        return []


def _adaptive_quality_row_outcome_v745(row):
    row = row or {}
    status = ""
    try:
        status = str(_testnet_lifecycle_user_status_v744(row) or "").upper()
    except Exception:
        status = str(row.get("status") or "").upper()
    pnl = row.get("pnl") or {}
    if pnl.get("status") == "ATTRIBUTED":
        realized = _safe_float(pnl.get("realized_usdt"), 0) or 0
        if realized > 0:
            return "win"
        if realized < 0:
            return "loss"
        return "flat"
    if status == "CLOSED_WIN":
        return "win"
    if status == "CLOSED_LOSS":
        return "loss"
    if status == "CLOSED_FLAT":
        return "flat"
    if status in {"NEEDS_ATTENTION", "EMERGENCY_CLOSED", "ENTRY_REJECTED", "PROTECTION_REJECTED", "ORPHAN_CLEANED"}:
        return "issue"
    return "pending"


def _adaptive_quality_stats_v745(chat_id=None, limit=ADAPTIVE_GATE_LOCAL_ROW_LIMIT_V745):
    stats = {}
    rows = _adaptive_quality_local_rows_v745(chat_id, limit)
    for row in rows:
        candidate_like = {
            "ticker": row.get("ticker"),
            "interval": row.get("interval"),
            "direction": row.get("direction"),
            "strategy": row.get("strategy"),
        }
        outcome = _adaptive_quality_row_outcome_v745(row)
        for key in _adaptive_quality_candidate_keys_v745(candidate_like):
            bucket = stats.setdefault(key, {
                "key": key,
                "wins": 0,
                "losses": 0,
                "flats": 0,
                "issues": 0,
                "pending": 0,
            })
            if outcome == "win":
                bucket["wins"] += 1
            elif outcome == "loss":
                bucket["losses"] += 1
            elif outcome == "flat":
                bucket["flats"] += 1
            elif outcome == "issue":
                bucket["issues"] += 1
            else:
                bucket["pending"] += 1
    for bucket in stats.values():
        closed = int(bucket["wins"] + bucket["losses"] + bucket["flats"])
        observed = int(closed + bucket["issues"])
        bucket["closed"] = closed
        bucket["observed"] = observed
        bucket["winrate"] = (bucket["wins"] / closed) if closed else None
        bucket["issue_rate"] = (bucket["issues"] / observed) if observed else None
    return stats


def _adaptive_quality_reason_v745(key, bucket, kind):
    key_type, key_value = key
    closed = int(bucket.get("closed") or 0)
    observed = int(bucket.get("observed") or 0)
    if kind == "winrate":
        wr = bucket.get("winrate")
        wr_txt = "n/a" if wr is None else f"{wr * 100:.0f}%"
        return f"{key_type} {key_value} WR {wr_txt} n={closed}"
    issue_rate = bucket.get("issue_rate")
    issue_txt = "n/a" if issue_rate is None else f"{issue_rate * 100:.0f}%"
    return f"{key_type} {key_value} issues {issue_txt} n={observed}"


def _adaptive_quality_penalty_v745(chat_id, candidate):
    stats = _adaptive_quality_stats_v745(chat_id)
    penalty = 0
    reasons = []
    evidence = []
    for key in _adaptive_quality_candidate_keys_v745(candidate):
        bucket = stats.get(key)
        if not bucket:
            continue
        closed = int(bucket.get("closed") or 0)
        observed = int(bucket.get("observed") or 0)
        key_penalty = 0
        wr = bucket.get("winrate")
        if closed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and wr is not None:
            if wr < 0.35:
                key_penalty += 10
            elif wr < 0.45:
                key_penalty += 6
            elif closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745 and wr < 0.50:
                key_penalty += 4
            if key_penalty and closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745:
                key_penalty += 2
            if key_penalty:
                reasons.append(_adaptive_quality_reason_v745(key, bucket, "winrate"))
        issue_rate = bucket.get("issue_rate")
        if observed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and issue_rate is not None:
            if issue_rate >= 0.35:
                key_penalty += 6
            elif issue_rate >= 0.25:
                key_penalty += 4
            if issue_rate >= 0.25:
                reasons.append(_adaptive_quality_reason_v745(key, bucket, "issues"))
        if key_penalty:
            key_penalty = min(10, key_penalty)
            penalty += key_penalty
            evidence.append({
                "key": f"{key[0]}:{key[1]}",
                "penalty": key_penalty,
                "closed": closed,
                "observed": observed,
                "wins": int(bucket.get("wins") or 0),
                "losses": int(bucket.get("losses") or 0),
                "issues": int(bucket.get("issues") or 0),
                "winrate": round(wr, 4) if wr is not None else None,
                "issue_rate": round(issue_rate, 4) if issue_rate is not None else None,
            })
    penalty = min(ADAPTIVE_GATE_MAX_PENALTY_V745, int(penalty))
    if penalty >= ADAPTIVE_GATE_BLOCK_PENALTY_V745:
        mode = "strong_penalty"
    elif penalty > 0:
        mode = "soft_penalty"
    else:
        mode = "observe"
    return {
        "mode": mode,
        "penalty": penalty,
        "reasons": reasons[:5],
        "evidence": evidence[:6],
        "min_closed": ADAPTIVE_GATE_MIN_CLOSED_V745,
        "max_penalty": ADAPTIVE_GATE_MAX_PENALTY_V745,
    }


def _adaptive_quality_attach_v745(chat_id, candidate):
    quality = (candidate or {}).get("adaptive_quality")
    if not isinstance(quality, dict):
        quality = _adaptive_quality_penalty_v745(chat_id, candidate)
        if isinstance(candidate, dict):
            candidate["adaptive_quality"] = quality
    raw_score = _safe_float((candidate or {}).get("score"), 0) or 0
    adjusted = max(0.0, raw_score - float(quality.get("penalty") or 0))
    if isinstance(candidate, dict):
        candidate["adaptive_score"] = adjusted
    return quality


def _adaptive_quality_row_payload_v745(quality):
    quality = quality or {}
    return {
        "mode": quality.get("mode"),
        "penalty": int(quality.get("penalty") or 0),
        "reasons": [str(x)[:180] for x in list(quality.get("reasons") or [])[:5]],
        "evidence": list(quality.get("evidence") or [])[:6],
    }


def _testnet_candidate_block_reason_v735(chat_id, candidate, active_positions=None, pos_err=None, today_count=None):
    reason = _base_testnet_candidate_block_reason_v735_for_v745(
        chat_id,
        candidate,
        active_positions=active_positions,
        pos_err=pos_err,
        today_count=today_count,
    )
    if reason:
        return reason
    candidate = candidate or {}
    quality = _adaptive_quality_attach_v745(chat_id, candidate)
    penalty = int(quality.get("penalty") or 0)
    if penalty < ADAPTIVE_GATE_BLOCK_PENALTY_V745:
        return None
    ep = candidate.get("entry_plan") or {}
    entry_now = int(ep.get("entry_now_score", ep.get("score", 0)) or 0)
    setup = int(ep.get("setup_score", ep.get("score", 0)) or 0)
    if min(entry_now, setup) >= ADAPTIVE_GATE_EXCEPTION_SCORE_V745:
        return None
    return "adaptive quality gate: waits for cleaner setup"


def testnet_select_trade_candidate(chat_id):
    tried = []
    candidates = []
    blocked = []
    pairs = [(ticker, tf) for ticker in PAPER_TRADER_SCAN_TICKERS for tf in PAPER_TRADER_TFS]
    workers = min(PAPER_SCAN_WORKERS, len(pairs)) or 1
    active_positions, pos_err = _testnet_open_positions_v734()
    today_count = _testnet_today_real_entry_count_v734(chat_id)

    with _futures_v74.ThreadPoolExecutor(max_workers=workers, thread_name_prefix="testnet-scan") as pool:
        fut_to_pair = {
            pool.submit(_paper_scan_one_v74, chat_id, ticker, tf): (ticker, tf)
            for ticker, tf in pairs
        }
        for fut in _futures_v74.as_completed(fut_to_pair):
            ticker, tf = fut_to_pair[fut]
            try:
                row, found = fut.result()
                tried.append(row)
                candidates.extend(found)
            except Exception as e:
                tried.append({"ticker": ticker, "tf": tf, "error": str(e)})

    for cand in candidates:
        quality = _adaptive_quality_attach_v745(chat_id, cand)
        key = (cand.get("ticker"), cand.get("interval"))
        for row in tried:
            if (row.get("ticker"), row.get("tf")) == key:
                current = row.get("adaptive_quality") or {}
                if int(quality.get("penalty") or 0) > int(current.get("penalty") or -1):
                    row["adaptive_quality"] = _adaptive_quality_row_payload_v745(quality)
                break

    candidates.sort(
        key=lambda x: (
            _safe_float(x.get("adaptive_score"), x.get("score", 0)) or 0,
            _safe_float(x.get("score"), 0) or 0,
        ),
        reverse=True,
    )
    row_by_pair = {(row.get("ticker"), row.get("tf")): row for row in tried}
    for cand in candidates:
        reason = _testnet_candidate_block_reason_v735(
            chat_id,
            cand,
            active_positions=active_positions,
            pos_err=pos_err,
            today_count=today_count,
        )
        key = (cand.get("ticker"), cand.get("interval"))
        if reason:
            blocked.append({
                "ticker": cand.get("ticker"),
                "tf": cand.get("interval"),
                "strategy": cand.get("strategy"),
                "score": cand.get("score"),
                "adaptive_score": cand.get("adaptive_score"),
                "adaptive_quality": _adaptive_quality_row_payload_v745(cand.get("adaptive_quality")),
                "reason": reason,
            })
            if key in row_by_pair and not row_by_pair[key].get("testnet_gate"):
                row_by_pair[key]["testnet_gate"] = reason
            continue
        cand["scan_total_candidates"] = len(candidates)
        cand["scan_blocked"] = blocked[:PAPER_TRADER_MAX_CANDIDATES_SHOWN]
        cand["scan_tried"] = tried
        try:
            data = cand.get("data") or {}
            data["futures_context"] = build_futures_context(cand.get("ticker"), data.get("price"))
        except Exception:
            pass
        return cand, tried

    return None, tried


def _demo_scan_row_for_storage_v736(row):
    payload = _base_demo_scan_row_for_storage_v736_for_v745(row)
    if (row or {}).get("adaptive_quality"):
        payload["adaptive_quality"] = _adaptive_quality_row_payload_v745(row.get("adaptive_quality"))
    return payload


def _demo_candidate_for_storage_v736(candidate):
    payload = _base_demo_candidate_for_storage_v736_for_v745(candidate)
    if (candidate or {}).get("adaptive_quality"):
        payload["adaptive_quality"] = _adaptive_quality_row_payload_v745(candidate.get("adaptive_quality"))
        payload["adaptive_score"] = round(_safe_float(candidate.get("adaptive_score"), 0) or 0, 4)
    return payload


# ============================================================
# v7.46 - ADAPTIVE GATE SCAN CACHE
# ============================================================
# A market scan can produce many candidates. The adaptive gate reads the local
# lifecycle evidence once per scan, then reuses the same stats for every
# candidate. This keeps the smarter gate from becoming a responsiveness cost.

_base_adaptive_quality_penalty_v745_for_v746 = _adaptive_quality_penalty_v745
_base_testnet_select_trade_candidate_v745_for_v746 = testnet_select_trade_candidate
_adaptive_quality_scan_stats_cache_v746 = {}
_adaptive_quality_scan_stats_lock_v746 = threading.RLock()


def _adaptive_quality_cache_key_v746(chat_id):
    try:
        return _paper_chat_key(chat_id)
    except Exception:
        return str(chat_id)


def _adaptive_quality_penalty_from_stats_v746(stats, candidate):
    stats = stats or {}
    penalty = 0
    reasons = []
    evidence = []
    for key in _adaptive_quality_candidate_keys_v745(candidate):
        bucket = stats.get(key)
        if not bucket:
            continue
        closed = int(bucket.get("closed") or 0)
        observed = int(bucket.get("observed") or 0)
        key_penalty = 0
        wr = bucket.get("winrate")
        if closed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and wr is not None:
            if wr < 0.35:
                key_penalty += 10
            elif wr < 0.45:
                key_penalty += 6
            elif closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745 and wr < 0.50:
                key_penalty += 4
            if key_penalty and closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745:
                key_penalty += 2
            if key_penalty:
                reasons.append(_adaptive_quality_reason_v745(key, bucket, "winrate"))
        issue_rate = bucket.get("issue_rate")
        if observed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and issue_rate is not None:
            if issue_rate >= 0.35:
                key_penalty += 6
            elif issue_rate >= 0.25:
                key_penalty += 4
            if issue_rate >= 0.25:
                reasons.append(_adaptive_quality_reason_v745(key, bucket, "issues"))
        if key_penalty:
            key_penalty = min(10, key_penalty)
            penalty += key_penalty
            evidence.append({
                "key": f"{key[0]}:{key[1]}",
                "penalty": key_penalty,
                "closed": closed,
                "observed": observed,
                "wins": int(bucket.get("wins") or 0),
                "losses": int(bucket.get("losses") or 0),
                "issues": int(bucket.get("issues") or 0),
                "winrate": round(wr, 4) if wr is not None else None,
                "issue_rate": round(issue_rate, 4) if issue_rate is not None else None,
            })
    penalty = min(ADAPTIVE_GATE_MAX_PENALTY_V745, int(penalty))
    if penalty >= ADAPTIVE_GATE_BLOCK_PENALTY_V745:
        mode = "strong_penalty"
    elif penalty > 0:
        mode = "soft_penalty"
    else:
        mode = "observe"
    return {
        "mode": mode,
        "penalty": penalty,
        "reasons": reasons[:5],
        "evidence": evidence[:6],
        "min_closed": ADAPTIVE_GATE_MIN_CLOSED_V745,
        "max_penalty": ADAPTIVE_GATE_MAX_PENALTY_V745,
    }


def _adaptive_quality_penalty_v745(chat_id, candidate):
    cache_key = _adaptive_quality_cache_key_v746(chat_id)
    with _adaptive_quality_scan_stats_lock_v746:
        stats = _adaptive_quality_scan_stats_cache_v746.get(cache_key)
    if stats is None:
        return _base_adaptive_quality_penalty_v745_for_v746(chat_id, candidate)
    return _adaptive_quality_penalty_from_stats_v746(stats, candidate)


def testnet_select_trade_candidate(chat_id):
    cache_key = _adaptive_quality_cache_key_v746(chat_id)
    stats = _adaptive_quality_stats_v745(chat_id)
    with _adaptive_quality_scan_stats_lock_v746:
        _adaptive_quality_scan_stats_cache_v746[cache_key] = stats
    try:
        return _base_testnet_select_trade_candidate_v745_for_v746(chat_id)
    finally:
        with _adaptive_quality_scan_stats_lock_v746:
            _adaptive_quality_scan_stats_cache_v746.pop(cache_key, None)


# ============================================================
# v7.47 - ADAPTIVE EVIDENCE FRESHNESS WINDOW
# ============================================================
# Old trades still stay in the local journal, but adaptive setup quality uses
# fresh evidence only. This lowers overfitting to market regimes that may no
# longer describe today's futures market.

_base_adaptive_quality_local_rows_v745_for_v747 = _adaptive_quality_local_rows_v745
ADAPTIVE_GATE_FRESHNESS_DAYS_V747 = int(os.getenv("ADAPTIVE_GATE_FRESHNESS_DAYS", "90"))


def _adaptive_quality_row_dt_v747(row):
    row = row or {}
    raw = (
        row.get("updated_at")
        or row.get("closed_at")
        or row.get("created_at")
        or row.get("ts")
    )
    if not raw:
        return None
    try:
        return _safety_parse_dt_v716(raw)
    except Exception:
        return None


def _adaptive_quality_row_is_fresh_v747(row, now=None):
    dt = _adaptive_quality_row_dt_v747(row)
    if dt is None:
        return True
    now = now or datetime.now(timezone.utc)
    if dt.tzinfo is None:
        dt = dt.replace(tzinfo=timezone.utc)
    return dt >= now - timedelta(days=ADAPTIVE_GATE_FRESHNESS_DAYS_V747)


def _adaptive_quality_local_rows_v745(chat_id=None, limit=ADAPTIVE_GATE_LOCAL_ROW_LIMIT_V745):
    rows = _base_adaptive_quality_local_rows_v745_for_v747(chat_id, limit)
    now = datetime.now(timezone.utc)
    return [row for row in rows if _adaptive_quality_row_is_fresh_v747(row, now)]


# ============================================================
# v7.48 - ADAPTIVE PENALTY DE-DUPLICATION
# ============================================================
# Related evidence buckets can describe the same losing streak. Penalize by
# bucket groups instead of blindly summing ticker + TF + strategy duplicates.

_base_adaptive_quality_penalty_from_stats_v746_for_v748 = _adaptive_quality_penalty_from_stats_v746

ADAPTIVE_GATE_GROUP_CAPS_V748 = {
    "specific": 8,
    "strategy": 4,
    "asset": 3,
    "timeframe": 2,
    "direction": 1,
    "other": 2,
}
ADAPTIVE_GATE_GROUP_TOTAL_CAP_V748 = ADAPTIVE_GATE_BLOCK_PENALTY_V745


def _adaptive_quality_bucket_group_v748(key):
    key_type = (key or ("", ""))[0]
    if key_type in {"ticker_tf", "strategy_tf"}:
        return "specific"
    if key_type == "strategy":
        return "strategy"
    if key_type == "ticker":
        return "asset"
    if key_type == "tf":
        return "timeframe"
    if key_type == "direction":
        return "direction"
    return "other"


def _adaptive_quality_raw_bucket_penalty_v748(key, bucket):
    closed = int((bucket or {}).get("closed") or 0)
    observed = int((bucket or {}).get("observed") or 0)
    key_penalty = 0
    reasons = []
    wr = (bucket or {}).get("winrate")
    if closed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and wr is not None:
        if wr < 0.35:
            key_penalty += 10
        elif wr < 0.45:
            key_penalty += 6
        elif closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745 and wr < 0.50:
            key_penalty += 4
        if key_penalty and closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745:
            key_penalty += 2
        if key_penalty:
            reasons.append(_adaptive_quality_reason_v745(key, bucket, "winrate"))
    issue_rate = (bucket or {}).get("issue_rate")
    if observed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and issue_rate is not None:
        if issue_rate >= 0.35:
            key_penalty += 6
        elif issue_rate >= 0.25:
            key_penalty += 4
        if issue_rate >= 0.25:
            reasons.append(_adaptive_quality_reason_v745(key, bucket, "issues"))
    return min(10, key_penalty), reasons


def _adaptive_quality_penalty_from_stats_v746(stats, candidate):
    stats = stats or {}
    groups = {}
    for key in _adaptive_quality_candidate_keys_v745(candidate):
        bucket = stats.get(key)
        if not bucket:
            continue
        raw_penalty, reasons = _adaptive_quality_raw_bucket_penalty_v748(key, bucket)
        if raw_penalty <= 0:
            continue
        group = _adaptive_quality_bucket_group_v748(key)
        cap = int(ADAPTIVE_GATE_GROUP_CAPS_V748.get(group, ADAPTIVE_GATE_GROUP_CAPS_V748["other"]))
        group_penalty = min(cap, raw_penalty)
        current = groups.get(group)
        if current is not None and int(current.get("penalty") or 0) >= group_penalty:
            continue
        wr = bucket.get("winrate")
        issue_rate = bucket.get("issue_rate")
        groups[group] = {
            "group": group,
            "key": f"{key[0]}:{key[1]}",
            "penalty": group_penalty,
            "raw_penalty": raw_penalty,
            "closed": int(bucket.get("closed") or 0),
            "observed": int(bucket.get("observed") or 0),
            "wins": int(bucket.get("wins") or 0),
            "losses": int(bucket.get("losses") or 0),
            "issues": int(bucket.get("issues") or 0),
            "winrate": round(wr, 4) if wr is not None else None,
            "issue_rate": round(issue_rate, 4) if issue_rate is not None else None,
            "reasons": reasons[:3],
        }

    evidence = sorted(groups.values(), key=lambda x: int(x.get("penalty") or 0), reverse=True)
    penalty = sum(int(item.get("penalty") or 0) for item in evidence)
    penalty = min(ADAPTIVE_GATE_GROUP_TOTAL_CAP_V748, ADAPTIVE_GATE_MAX_PENALTY_V745, int(penalty))
    if penalty >= ADAPTIVE_GATE_BLOCK_PENALTY_V745:
        mode = "strong_penalty"
    elif penalty > 0:
        mode = "soft_penalty"
    else:
        mode = "observe"
    reasons = []
    for item in evidence:
        reasons.extend(list(item.get("reasons") or []))
    return {
        "mode": mode,
        "penalty": penalty,
        "reasons": reasons[:5],
        "evidence": evidence[:6],
        "min_closed": ADAPTIVE_GATE_MIN_CLOSED_V745,
        "max_penalty": ADAPTIVE_GATE_GROUP_TOTAL_CAP_V748,
        "dedup": "grouped",
    }


# ============================================================
# v7.49 - BAYESIAN ADAPTIVE WINRATE SHRINKAGE
# ============================================================
# Small samples are noisy. Use a neutral prior for adaptive quality penalties
# so 10 trades can warn the bot, but do not dominate the gate like 100 trades.

_base_adaptive_quality_penalty_v745_for_v749 = _adaptive_quality_penalty_v745
_base_adaptive_quality_raw_bucket_penalty_v748_for_v749 = _adaptive_quality_raw_bucket_penalty_v748

ADAPTIVE_GATE_WINRATE_PRIOR_TRADES_V749 = int(os.getenv("ADAPTIVE_GATE_WINRATE_PRIOR_TRADES", "8"))
ADAPTIVE_GATE_WINRATE_PRIOR_MEAN_V749 = float(os.getenv("ADAPTIVE_GATE_WINRATE_PRIOR_MEAN", "0.50"))


def _adaptive_quality_adjusted_winrate_v749(bucket):
    bucket = bucket or {}
    closed = int(bucket.get("closed") or 0)
    wins = int(bucket.get("wins") or 0)
    prior_n = max(0, int(ADAPTIVE_GATE_WINRATE_PRIOR_TRADES_V749))
    prior_mean = min(1.0, max(0.0, float(ADAPTIVE_GATE_WINRATE_PRIOR_MEAN_V749)))
    if closed <= 0 and prior_n <= 0:
        return None
    return (wins + prior_n * prior_mean) / max(1, closed + prior_n)


def _adaptive_quality_raw_bucket_penalty_v748(key, bucket):
    closed = int((bucket or {}).get("closed") or 0)
    observed = int((bucket or {}).get("observed") or 0)
    key_penalty = 0
    reasons = []
    wr = _adaptive_quality_adjusted_winrate_v749(bucket)
    if closed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and wr is not None:
        if wr < 0.35:
            key_penalty += 10
        elif wr < 0.45:
            key_penalty += 6
        elif closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745 and wr < 0.50:
            key_penalty += 4
        if key_penalty and closed >= ADAPTIVE_GATE_STRONG_CLOSED_V745:
            key_penalty += 2
        if key_penalty:
            raw_wr = (bucket or {}).get("winrate")
            reason = _adaptive_quality_reason_v745(key, bucket, "winrate")
            if raw_wr is not None:
                reason += f" | adj {wr * 100:.0f}%"
            reasons.append(reason)
    issue_rate = (bucket or {}).get("issue_rate")
    if observed >= ADAPTIVE_GATE_MIN_CLOSED_V745 and issue_rate is not None:
        if issue_rate >= 0.35:
            key_penalty += 6
        elif issue_rate >= 0.25:
            key_penalty += 4
        if issue_rate >= 0.25:
            reasons.append(_adaptive_quality_reason_v745(key, bucket, "issues"))
    return min(10, key_penalty), reasons


def _adaptive_quality_penalty_v745(chat_id, candidate):
    cache_key = _adaptive_quality_cache_key_v746(chat_id)
    with _adaptive_quality_scan_stats_lock_v746:
        stats = _adaptive_quality_scan_stats_cache_v746.get(cache_key)
    if stats is None:
        stats = _adaptive_quality_stats_v745(chat_id)
    return _adaptive_quality_penalty_from_stats_v746(stats, candidate)


# ============================================================
# v7.51 - TESTNET LIFECYCLE STATUS CLARITY
# ============================================================
# The public report should distinguish a local plan from an exchange-accepted
# trade. It also sorts by plan creation time, not lifecycle rebuild time.

_base_testnet_lifecycle_result_text_v744_for_v751 = _testnet_lifecycle_result_text_v744
_base_format_testnet_lifecycle_report_v744_for_v751 = format_testnet_lifecycle_report_v744


def _testnet_lifecycle_created_dt_v751(row):
    row = row or {}
    raw = row.get("created_at") or row.get("updated_at")
    if not raw:
        return datetime.min.replace(tzinfo=timezone.utc)
    try:
        dt = _safety_parse_dt_v716(raw)
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=timezone.utc)
        return dt
    except Exception:
        return datetime.min.replace(tzinfo=timezone.utc)


def _testnet_lifecycle_display_status_v751(row):
    status = _testnet_lifecycle_user_status_v744(row)
    return {
        "PLANNED": "PLAN_ONLY",
        "ENTRY_ACCEPTED": "ENTRY_ACCEPTED",
        "ENTRY_REJECTED": "ENTRY_REJECTED",
        "OPEN_PROTECTED": "OPEN_PROTECTED",
        "PNL_PENDING": "PNL_PENDING",
        "ORPHAN_CLEANED": "ORPHAN_CLEANED",
        "NEEDS_ATTENTION": "NEEDS_ATTENTION",
        "EMERGENCY_CLOSED": "EMERGENCY_CLOSED",
        "CLOSED_WIN": "CLOSED_WIN",
        "CLOSED_LOSS": "CLOSED_LOSS",
        "CLOSED_FLAT": "CLOSED_FLAT",
    }.get(status, status or "PLAN_ONLY")


def _testnet_plan_failure_hint_v751(plan_id):
    if not plan_id:
        return ""
    try:
        events = [
            e for e in (_execution_load_state_v715().get("events") or [])
            if e.get("plan_id") == plan_id
            and e.get("ok") is False
        ]
    except Exception:
        events = []
    for event in events:
        response = event.get("response") or {}
        msg = response.get("msg") or event.get("reason")
        code = response.get("code")
        if msg:
            prefix = f"{code}: " if code is not None else ""
            return _ui_short_text(prefix + str(msg), 120)
        for order in list(event.get("orders") or []):
            response = order.get("response") or {}
            msg = response.get("msg") or order.get("reason")
            code = response.get("code")
            if msg:
                prefix = f"{code}: " if code is not None else ""
                return _ui_short_text(prefix + str(msg), 120)
    return ""


def _testnet_lifecycle_result_text_v744(row):
    status = _testnet_lifecycle_user_status_v744(row)
    if status == "PLANNED":
        return "plan only, order not sent"
    if status == "ENTRY_REJECTED":
        hint = _testnet_plan_failure_hint_v751((row or {}).get("plan_id"))
        return "rejected" + (f": {hint}" if hint else "")
    return _base_testnet_lifecycle_result_text_v744_for_v751(row)


def format_testnet_lifecycle_report_v744(chat_id, limit=8):
    stats = _testnet_public_stats_v738(chat_id)
    rows = list(_testnet_lifecycle_recent_v740(chat_id, 50) or [])
    rows.sort(key=_testnet_lifecycle_created_dt_v751, reverse=True)
    linked = int(stats.get("attributed_closed") or 0)
    pending = max(0, int(stats.get("bot_closed") or 0) - linked)
    issues = _testnet_lifecycle_issue_count_v744(rows)
    lines = [
        "📒 <b>Demo Trade Report</b>",
        "",
        f"Открытые: <b>{stats.get('open', 0)}/{PAPER_TRADER_MAX_POSITIONS}</b>",
        f"Закрытые: <b>{stats.get('bot_closed', 0)}</b> | PnL linked: <b>{linked}</b>",
        _testnet_public_pnl_line_v738(stats),
        f"Сверяется: <b>{pending}</b> | Проблемы в журнале: <b>{issues}</b>",
        "",
        "<b>Последние планы / сделки:</b>",
    ]
    if not rows:
        lines.append("Пока нет Testnet-сделок бота.")
        return "\n".join(lines)
    for row in rows[: int(limit)]:
        ticker = _ui_ticker_short(row.get("ticker"))
        direction = str(row.get("direction") or "").upper()
        interval = _ui_tf_short(row.get("interval"))
        status = _testnet_lifecycle_display_status_v751(row)
        result = _testnet_lifecycle_result_text_v744(row)
        lines.append(f"• {ticker} {direction} {interval} | <b>{_ui_html(status)}</b> | {_ui_html(result)}")
    if pending:
        lines += ["", "PnL может появиться позже: Binance income иногда приходит не сразу."]
    if issues:
        lines += ["", "Проблемные статусы записаны локально. PLAN_ONLY не является открытой сделкой."]
    return "\n".join(lines)


