# ============================================================
# v7.54 - ROBUST TESTNET SUBMIT PIPELINE
# ============================================================
# The demo bot must not stop after entry /order/test. Run and record every
# stage explicitly so a valid candidate reaches real Testnet entry, or the user
# sees the exact stage that blocked it.

_base_submit_testnet_trade_v753_for_v754 = _submit_testnet_trade_v734


def _testnet_stage_error_v754(plan, stage, exc):
    return {
        "ts": datetime.now(timezone.utc).isoformat(),
        "plan_id": (plan or {}).get("plan_id"),
        "mode": execution_mode().get("mode"),
        "submitted": False,
        "ok": False,
        "skipped": True,
        "stage": stage,
        "reason": f"{stage} exception: {type(exc).__name__}: {str(exc)[:220]}",
        "error": str(exc)[:500],
    }


def _testnet_result_reason_v754(result):
    result = result or {}
    reason = result.get("reason") or result.get("error")
    response = result.get("response")
    if isinstance(response, dict):
        reason = reason or response.get("msg") or response.get("code")
    orders = result.get("orders")
    if not reason and isinstance(orders, list):
        bad = [x for x in orders if not x.get("ok")]
        if bad:
            reason = "; ".join(
                f"{x.get('label') or 'order'}: {x.get('reason') or x.get('status_code')}"
                for x in bad[:3]
            )
    return str(reason or "unknown")[:500]


def _submit_testnet_trade_v734(chat_id, candidate):
    try:
        plan = _build_testnet_trade_plan_v734(chat_id, candidate)
    except Exception as e:
        return {"ok": False, "stage": "plan", "plan": {}, "reason": f"plan exception: {type(e).__name__}: {str(e)[:220]}"}

    if plan.get("blockers"):
        _execution_record_plan_v715(plan)
        return {"ok": False, "stage": "plan", "plan": plan, "reason": "; ".join(plan.get("blockers") or [])}

    try:
        entry_test = submit_testnet_order_test(plan)
    except Exception as e:
        entry_test = _testnet_stage_error_v754(plan, "entry_test", e)

    try:
        protection_test = submit_testnet_protection_order_tests(plan)
    except Exception as e:
        protection_test = _testnet_stage_error_v754(plan, "protection_test", e)

    if not entry_test.get("ok") or not protection_test.get("ok"):
        _record_testnet_trade_attempt_v734(plan, entry_test, protection_test)
        return {
            "ok": False,
            "stage": "validation",
            "plan": plan,
            "entry_test": entry_test,
            "protection_test": protection_test,
            "reason": _testnet_result_reason_v754(entry_test)
            if not entry_test.get("ok")
            else _testnet_result_reason_v754(protection_test),
        }

    try:
        leverage = submit_testnet_set_leverage(plan)
    except Exception as e:
        leverage = _testnet_stage_error_v754(plan, "leverage", e)

    try:
        entry = submit_testnet_real_entry_order(plan, {"entry_test_ok": True, "protection_test_ok": True})
    except Exception as e:
        entry = _testnet_stage_error_v754(plan, "real_entry", e)

    protection = None
    emergency = None
    if entry.get("ok"):
        try:
            protection = submit_testnet_real_protection_orders(plan, entry)
        except Exception as e:
            protection = _testnet_stage_error_v754(plan, "real_protection", e)
        if not protection.get("ok"):
            try:
                emergency = submit_testnet_emergency_close_order(plan, "protection_failed_after_entry")
            except Exception as e:
                emergency = _testnet_stage_error_v754(plan, "emergency_close", e)

    _record_testnet_trade_attempt_v734(plan, entry_test, protection_test, leverage, entry, protection, emergency)

    if not entry.get("ok"):
        return {"ok": False, "stage": "entry", "plan": plan, "entry": entry, "reason": _testnet_result_reason_v754(entry)}
    if not protection or not protection.get("ok"):
        return {
            "ok": False,
            "stage": "protection",
            "plan": plan,
            "entry": entry,
            "protection": protection,
            "emergency": emergency,
            "reason": _testnet_result_reason_v754(protection or {"reason": "protection order rejected"}),
        }

    monitor = _testnet_monitor_for_plan_v737(plan, delay_sec=0.2)
    return {
        "ok": True,
        "stage": "done",
        "plan": plan,
        "entry": entry,
        "protection": protection,
        "leverage": leverage,
        "monitor": monitor,
    }


# ============================================================
# v7.55 - RUNTIME DIAGNOSTICS SCREEN
# ============================================================
# Compact Telegram diagnostics for the exact problems that hurt live Testnet
# verification: stale duplicate processes, real-submit flags and last execution
# stage. No secrets are displayed.

_base_autobot_keyboard_v754_for_v755 = autobot_keyboard
_base_async_handle_update_v754_for_v755 = async_handle_update


def _runtime_bot_runtime_path_v756():
    return os.path.normcase(os.path.abspath(os.path.join(os.path.dirname(__file__), "bot_runtime.py")))


def _runtime_python_process_rows_v756():
    import subprocess
    cmd = (
        "[Console]::OutputEncoding=[System.Text.Encoding]::UTF8; "
        "Get-CimInstance Win32_Process | "
        "Where-Object { $_.Name -match 'python' -and $_.CommandLine } | "
        "Select-Object ProcessId,ParentProcessId,CommandLine | ConvertTo-Json -Compress"
    )
    result = subprocess.run(
        ["powershell.exe", "-NoProfile", "-Command", cmd],
        capture_output=True,
        text=True,
        timeout=4,
    )
    raw = (result.stdout or "").strip()
    if not raw:
        return []
    payload = json.loads(raw)
    return payload if isinstance(payload, list) else [payload]


def _runtime_bot_processes_v755():
    current_pid = os.getpid()
    if os.name != "nt":
        return [{"pid": current_pid, "current": True, "command": "current python process"}]
    try:
        runtime_path = _runtime_bot_runtime_path_v756()
        out = []
        for row in _runtime_python_process_rows_v756():
            command = str(row.get("CommandLine") or "")
            normalized_command = os.path.normcase(command.replace('"', ""))
            if runtime_path not in normalized_command:
                continue
            pid = int(row.get("ProcessId") or 0)
            out.append({
                "pid": pid,
                "parent_pid": int(row.get("ParentProcessId") or 0),
                "current": pid == current_pid,
                "command": command[:220],
            })
        if len(out) > 1:
            exact_pids = {row["pid"] for row in out}
            wrapper_parent_pids = {
                row["parent_pid"]
                for row in out
                if row.get("parent_pid") in exact_pids
            }
            out = [row for row in out if row["pid"] not in wrapper_parent_pids]
        return out or [{"pid": current_pid, "parent_pid": 0, "current": True, "command": f"current process; exact runtime path not found: {os.path.basename(runtime_path)}"}]
    except Exception as e:
        return [{"pid": current_pid, "current": True, "command": f"process scan failed: {type(e).__name__}"}]


def _runtime_latest_chain_v755(chat_id=None):
    try:
        state = _execution_load_state_v715()
    except Exception as e:
        return {"error": f"execution state load failed: {e}"}
    key = _paper_chat_key(chat_id) if chat_id is not None else None
    plans = list(state.get("plans") or [])
    if key is not None:
        plans = [p for p in plans if str(p.get("chat_id")) == key]
    plans.sort(key=lambda p: str(p.get("created_at") or p.get("ts") or ""))
    plan = plans[-1] if plans else None
    if not plan:
        return {"plan": None, "events": [], "hint": "ещё нет ордер-планов"}
    plan_id = plan.get("plan_id")
    events = [
        e for e in list(state.get("events") or [])
        if e.get("plan_id") == plan_id
    ]
    events.sort(key=lambda e: str(e.get("ts") or ""))
    latest = events[-1] if events else None
    stages = {
        "entry_test": False,
        "protection_test": False,
        "real_entry": False,
        "real_protection": False,
        "monitor": False,
    }
    for event in events:
        event_type = str(event.get("type") or "")
        kind = str(event.get("kind") or "")
        ok = bool(event.get("ok"))
        if event_type == "testnet_order_test":
            stages["entry_test"] = stages["entry_test"] or ok
        elif event_type == "testnet_protection_order_test" or kind in {"protection", "real_protection"}:
            if kind == "real_protection":
                stages["real_protection"] = stages["real_protection"] or ok
            else:
                stages["protection_test"] = stages["protection_test"] or ok
        elif event_type == "testnet_real_order":
            if kind == "real_entry":
                stages["real_entry"] = stages["real_entry"] or ok
            elif kind == "real_protection":
                stages["real_protection"] = stages["real_protection"] or ok
        elif event_type == TESTNET_MONITOR_EVENTS_FILE_KIND:
            stages["monitor"] = True
    if stages["real_entry"]:
        hint = "real entry записан"
        if stages["real_protection"]:
            hint += " + защита записана"
        elif stages["protection_test"]:
            hint += ", но real protection ещё не записан"
    elif stages["protection_test"]:
        hint = "валидация защиты OK, real entry не записан"
    elif stages["entry_test"]:
        hint = "entry-test OK, но protection/real-entry не записаны; возможен старый процесс"
    else:
        hint = "реальный entry ещё не доходил до проверки"
    return {"plan": plan, "events": events, "latest": latest, "stages": stages, "hint": hint}


def _runtime_event_label_v755(event):
    if not event:
        return "нет событий"
    name = event.get("kind") or event.get("type") or "event"
    status = "OK" if event.get("ok") else ("SKIP" if event.get("skipped") else "BLOCK")
    reason = _testnet_result_reason_v754(event) if not event.get("ok") else ""
    if reason and reason != "unknown":
        return f"{name} | {status} | {_ui_short_text(reason, 120)}"
    return f"{name} | {status}"


